mapper.select:
select r.id, r.reporter_id as reporter_id, m.nickname as reporter_nickname, r.target_type as target_type, r.target_id as target_id, r.reason, r.detail, r.status, r.resolved_at as resolved_at, r.created_datetime as created_datetime from tbl_report r join tbl_member m on r.reporter_id = m.id
and r.target_type = #{targetType}
and r.status = #{status}
and r.reporter_id = #{reporterId}
order by r.created_datetime desc limit #{size} offset (#{page} - 1) * #{size}

select count(*)
from tbl_report r


        and r.target_type = #{targetType}


        and r.status = #{status}


        and r.reporter_id = #{reporterId}
